create procedure [CREATE_TXPD] @FromDate datetime, @ToDate datetime, @Tablename as varchar(50) output AS IF OBJECT_ID('dbo.TXPD','U') IS NOT NULL     DROP TABLE TXPD CREATE TABLE TXPD ([Invoice Number] varchar(21) , [Invoice date] datetime , [GSTIN/UIN] varchar(32) , [Document Number] varchar(21) , [Document Date] datetime ,[Total Invoice Value] decimal, [Type] varchar(8) , [IGST Rate] decimal , [IGST Amount] decimal , [CGST Rate] decimal , [CGST Amount] decimal , [SGST Rate] decimal , [SGST Amount] decimal , [CESS Rate] decimal , [CESS Amount] decimal ,) Set @Tablename='TXPD' Select @Tablename